function sortedSquares(a) {
  const n = a.length, res = new Array(n);
  let lo = 0, hi = n - 1;
  for (let i = n - 1; i >= 0; i--) {
    if (Math.abs(a[lo]) > Math.abs(a[hi])) { res[i] = a[lo] * a[lo]; lo++; }
    else { res[i] = a[hi] * a[hi]; hi--; }
  }
  return res;
}

